local normalArrowId = ItemID.ARROW

function CustomShopEffectArrow:onEquipGoods(player, goods)
    local effectArrow = self.Settings[goods.SettingId]
    if not effectArrow then
        return
    end
    ---获取原来的装备的箭装扮
    local oldArrowId = player.equip_dress[tostring(normalArrowId)] or normalArrowId
    ---设置新的箭装扮
    player.equip_dress[tostring(normalArrowId)] = effectArrow.EffectArrowId
    local inv = player:getInventory()
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id == oldArrowId then
            inv:decrStackSize(index, info.num)
            player:tryAddItem(normalArrowId, info.num)
        end
    end
end

function CustomShopEffectArrow:onUnloadGoods(player, goods)
    local effectArrow = self.Settings[goods.SettingId]
    if not effectArrow then
        return
    end
    local oldArrowId = effectArrow.EffectArrowId
    --oldArrowId = player:tryItemId2DressId(oldArrowId)
    player.equip_dress[tostring(normalArrowId)] = nil
    local inv = player:getInventory()
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id == oldArrowId then
            inv:decrStackSize(index, info.num)
            player:tryAddItem(normalArrowId, info.num)
        end
    end
end